-- ============================================================================
-- vol_inscricoes · armazena cada inscricao no formulario Google de voluntariado
-- com nome individual para cruzamento de dados (batismos, NEXT, grupos, etc).
--
-- Motivo: dados_brutos so guarda agregados mensais (numero), perdendo a
-- granularidade de pessoa. Sem nomes, nao da pra responder perguntas como
-- "quantos batizados em 2026 tambem se inscreveram pra ser voluntarios?".
--
-- Fonte: planilha "Inscricao voluntariado (respostas)" (Google Form).
-- 749 inscricoes, periodo 2024-02 a 2026-05.
-- ============================================================================

CREATE TABLE IF NOT EXISTS public.vol_inscricoes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  -- Identificacao
  nome text NOT NULL,
  sobrenome text NOT NULL,
  nome_completo text NOT NULL,
  cpf text,
  email text,
  telefone text,
  data_nascimento date,
  nome_mae text,
  -- Inscricao
  data_inscricao timestamptz NOT NULL,
  participou_next text,
  dom_predominante text,
  ministerios_interesse text,
  area text NOT NULL CHECK (area IN ('kids','sede','ami','bridge','online')),
  -- Funil
  status text NOT NULL CHECK (status IN (
    'inscrito','enviado_ministerio','integrado','kids',
    'nao_responde','nao_pode_ou_duplicata'
  )),
  primeiro_contato_em text,
  enviado_lider_em text,
  feedback text,
  integrado_em text,
  -- Cross-reference (FKs opcionais)
  membro_id uuid REFERENCES public.mem_membros(id) ON DELETE SET NULL,
  vol_profile_id uuid REFERENCES public.vol_profiles(id) ON DELETE SET NULL,
  visitante_id uuid REFERENCES public.int_visitantes(id) ON DELETE SET NULL,
  -- Audit
  origem text NOT NULL DEFAULT 'form_google',
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_cpf
  ON public.vol_inscricoes (cpf) WHERE cpf IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_email
  ON public.vol_inscricoes (lower(email)) WHERE email IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_nome
  ON public.vol_inscricoes (lower(nome_completo));
CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_data
  ON public.vol_inscricoes (data_inscricao DESC);
CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_status
  ON public.vol_inscricoes (status);
CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_area
  ON public.vol_inscricoes (area);
CREATE INDEX IF NOT EXISTS idx_vol_inscricoes_membro
  ON public.vol_inscricoes (membro_id) WHERE membro_id IS NOT NULL;

ALTER TABLE public.vol_inscricoes ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "service_role_vol_inscricoes" ON public.vol_inscricoes;
CREATE POLICY "service_role_vol_inscricoes"
  ON public.vol_inscricoes FOR ALL TO service_role USING (true);
DROP POLICY IF EXISTS "auth_read_vol_inscricoes" ON public.vol_inscricoes;
CREATE POLICY "auth_read_vol_inscricoes"
  ON public.vol_inscricoes FOR SELECT TO authenticated USING (true);
DROP POLICY IF EXISTS "auth_write_vol_inscricoes" ON public.vol_inscricoes;
CREATE POLICY "auth_write_vol_inscricoes"
  ON public.vol_inscricoes FOR INSERT TO authenticated WITH CHECK (true);
DROP POLICY IF EXISTS "auth_update_vol_inscricoes" ON public.vol_inscricoes;
CREATE POLICY "auth_update_vol_inscricoes"
  ON public.vol_inscricoes FOR UPDATE TO authenticated USING (true);

COMMENT ON TABLE public.vol_inscricoes IS
  'Inscricoes individuais do formulario Google de voluntariado. Cada linha = uma pessoa que se inscreveu. Usado para cruzamento com batismos, NEXT, grupos, etc.';

