-- ----------------------------------------------------------------------------
-- Match com mem_membros (CPF primeiro, depois email + nascimento)
-- ----------------------------------------------------------------------------

-- 1. Match exato por CPF (583 inscricoes tem CPF)
UPDATE public.vol_inscricoes vi
   SET membro_id = m.id
  FROM public.mem_membros m
 WHERE vi.cpf IS NOT NULL
   AND m.cpf IS NOT NULL
   AND regexp_replace(m.cpf, '\D', '', 'g') = vi.cpf
   AND vi.membro_id IS NULL;

-- 2. Match por email (case insensitive) entre os que ainda nao bateram por CPF
UPDATE public.vol_inscricoes vi
   SET membro_id = m.id
  FROM public.mem_membros m
 WHERE vi.email IS NOT NULL
   AND m.email IS NOT NULL
   AND lower(trim(m.email)) = lower(trim(vi.email))
   AND vi.membro_id IS NULL;

-- 3. Match por nome+data_nascimento (fallback fraco)
UPDATE public.vol_inscricoes vi
   SET membro_id = m.id
  FROM public.mem_membros m
 WHERE vi.data_nascimento IS NOT NULL
   AND m.data_nascimento IS NOT NULL
   AND vi.data_nascimento = m.data_nascimento
   AND lower(trim(m.nome)) = lower(trim(vi.nome_completo))
   AND vi.membro_id IS NULL;

